import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Specialty Labs","description":"","frontmatter":{},"headers":[],"relativePath":"guide/specialty-labs.md","filePath":"guide/specialty-labs.md","lastUpdated":1772287587000}'),o={name:"guide/specialty-labs.md"};function i(l,e,n,d,p,c){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="specialty-labs" tabindex="-1">Specialty Labs <a class="header-anchor" href="#specialty-labs" aria-label="Permalink to &quot;Specialty Labs&quot;">​</a></h1><p>Beyond standard blood work, getbased supports specialty lab tests including Organic Acids Tests (OAT), amino acid panels, fatty acid profiles, toxic element screens, DUTCH hormone panels, Hair Tissue Mineral Analysis (HTMA), and GI panels. Import works the same way — drop the PDF and the AI handles the rest.</p><h2 id="supported-test-types" tabindex="-1">Supported Test Types <a class="header-anchor" href="#supported-test-types" aria-label="Permalink to &quot;Supported Test Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Test Type</th><th>Examples</th></tr></thead><tbody><tr><td>OAT</td><td>Mosaic, Genova, Great Plains organic acids</td></tr><tr><td>Amino Acids</td><td>Plasma or urine amino acid profiles</td></tr><tr><td>Fatty Acids</td><td>Omega-3 index, fatty acid panels</td></tr><tr><td>Toxic Elements</td><td>Heavy metals, toxic element screens</td></tr><tr><td>DUTCH</td><td>Dried urine hormone panels</td></tr><tr><td>HTMA</td><td>Hair Tissue Mineral Analysis</td></tr><tr><td>GI</td><td>Stool analysis, gut health panels</td></tr></tbody></table><p>Any lab report that isn&#39;t standard blood work is auto-detected and routed through the specialty pipeline.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Drop your PDF</strong> on the dashboard — same as any other import</li><li><strong>AI detects the test type</strong> — the AI reads the report and identifies whether it&#39;s blood work, OAT, DUTCH, or another type</li><li><strong>Markers are mapped</strong> with test-type-prefixed categories (e.g., <code>oatNutritional</code>, <code>dutchHormones</code>) to keep specialty results separate from standard blood markers</li><li><strong>Reference ranges come from your PDF</strong> — the AI extracts the lab&#39;s stated ranges rather than using built-in defaults</li><li><strong>Review and confirm</strong> in the import preview, then your results appear in charts</li></ol><div class="tip custom-block"><p class="custom-block-title">Your lab&#39;s reference ranges</p><p>Unlike standard blood markers that use built-in reference ranges, specialty markers use the ranges printed on your specific lab report. This means your charts reflect the ranges your lab considers normal.</p></div><h2 id="custom-marker-pipeline" tabindex="-1">Custom Marker Pipeline <a class="header-anchor" href="#custom-marker-pipeline" aria-label="Permalink to &quot;Custom Marker Pipeline&quot;">​</a></h2><p>Specialty markers flow through the <a href="./custom-markers.html">custom marker</a> pipeline. For each marker the AI extracts:</p><ul><li>A <strong>key</strong> with a test-type-prefixed category (e.g., <code>oatMicrobial.someMarker</code>)</li><li>A <strong>name</strong> in plain English</li><li>The <strong>unit</strong> of measurement</li><li><strong>Reference ranges</strong> from the lab report</li><li>A <strong>group</strong> tag (e.g., &quot;OAT&quot;, &quot;DUTCH&quot;) for sidebar organization</li></ul><p>These are created automatically during import — no manual setup required.</p><h2 id="sidebar-grouping" tabindex="-1">Sidebar Grouping <a class="header-anchor" href="#sidebar-grouping" aria-label="Permalink to &quot;Sidebar Grouping&quot;">​</a></h2><p>Specialty categories appear under collapsible group headers in the sidebar. For example, an OAT import creates categories like &quot;Microbial Overgrowth&quot;, &quot;Nutritional Markers&quot;, and &quot;Oxalate Markers&quot; — all grouped under an <strong>OAT</strong> header you can expand or collapse.</p><p>Click the group header to toggle visibility. Collapse state is remembered across sessions.</p><h2 id="importing-multiple-specialty-tests" tabindex="-1">Importing Multiple Specialty Tests <a class="header-anchor" href="#importing-multiple-specialty-tests" aria-label="Permalink to &quot;Importing Multiple Specialty Tests&quot;">​</a></h2><p>If you import multiple reports of the same test type over time, the markers are matched to existing custom marker definitions. This gives you trend tracking across specialty labs just like standard blood work.</p><div class="warning custom-block"><p class="custom-block-title">Model consistency</p><p>Use the same AI model for all imports of a given test type. Different models may generate different marker keys for the same test, which prevents proper trend tracking. See <a href="./ai-providers.html#model-consistency">AI Providers</a> for details.</p></div>',18)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
